/**
 * @summary Get daily compliance report
 */
export const getGetDailyReportUrl = (params?: GetDailyReportParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/reports/daily?${stringifiedParams}`
    : `/api/reports/daily`;
};

export const getDailyReport = async (
  params?: GetDailyReportParams,
  options?: RequestInit,
): Promise<DailyReport> => {
  return customFetch<DailyReport>(getGetDailyReportUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetDailyReportQueryKey = (params?: GetDailyReportParams) => {
  return [`/api/reports/daily`, ...(params ? [params] : [])] as const;
};

